INSERT INTO nightclub_quests (club_id, npc_id, title, description, quest_type, energy_cost, rewards, dialogue, chain_id, chain_position) VALUES
('410ad098-c58c-4d93-8efc-82ddb75d4d14', 'cake_dj_park', 'K-House Pioneer', 'Park Hye Jin wants to collaborate on a Korean house set.', 'one_time', 15, '{"cash": 300, "fame": 70, "xp": 30}', '[{"id":"d1","speaker":"Park Hye Jin","text":"Korean electronic music is having its moment. Want to help me push it further?","choices":[{"id":"c1a","text":"Absolutely. East meets West on the decks.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I''d love to learn from the Seoul scene.","next_node_id":"d2","effects":{"respect":4}}]},{"id":"d2","speaker":"Park Hye Jin","text":"Let''s do a B2B. Itaewon won''t know what hit it.","choices":[{"id":"c2","text":"Let''s go!","next_node_id":null}]}]', NULL, NULL),

('fbf18fea-bd74-49c1-8a1f-214fbea21395', 'beam_dj_sunju', 'Bangkok Deep', 'Sunju Hargun invites you to explore Bangkok''s deep house scene.', 'one_time', 15, '{"cash": 250, "fame": 60, "xp": 25}', '[{"id":"d1","speaker":"Sunju Hargun","text":"Bangkok is the hidden gem of Asian nightlife. Deep house thrives here. Can you feel it?","choices":[{"id":"c1a","text":"The heat, the energy — it''s perfect for deep grooves.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"I want to understand what makes Bangkok unique.","next_node_id":"d2","effects":{"respect":3}}]},{"id":"d2","speaker":"Sunju Hargun","text":"Come to the rooftop session. Sunset to sunrise. You''ll understand everything.","choices":[{"id":"c2","text":"Count me in.","next_node_id":null}]}]', NULL, NULL),

('56d00bb5-4087-46b5-a452-9181d747bd61', 'laundry_dj_touch', 'Nu-Disco Down Under', 'Touch Sensitive wants to hear your take on Australian nu-disco.', 'one_time', 15, '{"cash": 300, "fame": 65, "xp": 25}', '[{"id":"d1","speaker":"Touch Sensitive","text":"Mate, Sydney''s dance scene is special. We''ve got our own flavor — nu-disco, house, weird pop. You game?","choices":[{"id":"c1a","text":"I love genre-bending. Let''s make something fresh.","next_node_id":"d2","effects":{"affinity":5}},{"id":"c1b","text":"Show me the Sydney sound. I''m all ears.","next_node_id":"d2","effects":{"respect":3}}]},{"id":"d2","speaker":"Touch Sensitive","text":"Beauty. Friday night at the Laundry. Bring your weirdest records.","choices":[{"id":"c2","text":"You won''t be disappointed.","next_node_id":null}]}]', NULL, NULL);
